site_id = #{siteId}, panel_nm = #{panelNm}, panel_type_cd = #{panelTypeCd}, path_id = #{pathId}, visibility_targets = #{visibilityTargets}, use_yn = #{useYn}, use_start_date = #{useStartDate}, use_end_date = #{useEndDate}, disp_panel_status_cd = #{dispPanelStatusCd}, disp_panel_status_cd_before = #{dispPanelStatusCdBefore}, content_json = #{contentJson}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE p.panel_id = #{panelId}
